# Configuration
ALLOWED_METHODS = ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS']
MAX_REQUEST_SIZE = 1024 * 1024  # 1MB
RATE_LIMIT_WINDOW = 60  # seconds
RATE_LIMIT_MAX_REQUESTS = 100

# In-memory rate limiting (use Redis/Memorystore in production)
rate_limit_store = {}

def validate_request_size(request: Request) -> bool:
    """Validate request size to prevent DoS attacks"""
    content_length = request.content_length
    if content_length and content_length > MAX_REQUEST_SIZE:
        return False
    return True

def sanitize_input(data):
    """Sanitize input data to prevent injection attacks"""
    if isinstance(data, dict):
        return {k: sanitize_input(v) for k, v in data.items()}
    elif isinstance(data, list):
        return [sanitize_input(item) for item in data]
    elif isinstance(data, str):
        # Remove potential script tags and SQL injection patterns
        data = re.sub(r'<script[^>]*>.*?</script>', '', data, flags=re.IGNORECASE | re.DOTALL)
        data = re.sub(r'javascript:', '', data, flags=re.IGNORECASE)
        data = re.sub(r'on\w+\s*=', '', data, flags=re.IGNORECASE)
        return data.strip()
    return data

def check_rate_limit(client_id: str) -> bool:
    """Simple rate limiting implementation"""
    current_time = time.time()
    
    if client_id not in rate_limit_store:
        rate_limit_store[client_id] = []
    
    # Clean old requests outside the window
    rate_limit_store[client_id] = [
        req_time for req_time in rate_limit_store[client_id]
        if current_time - req_time < RATE_LIMIT_WINDOW
    ]
    
    # Check if limit exceeded
    if len(rate_limit_store[client_id]) >= RATE_LIMIT_MAX_REQUESTS:
        return False
    
    # Add current request
    rate_limit_store[client_id].append(current_time)
    return True

def verify_api_key(request: Request) -> bool:
    """Verify API key from environment variable"""
    api_key = os.environ.get('API_KEY')
    
    # If API_KEY is not set, skip verification (not recommended for production)
    if not api_key:
        return True
    
    # Check Authorization header
    auth_header = request.headers.get('Authorization', '')
    
    if not auth_header.startswith('Bearer '):
        return False
    
    provided_key = auth_header[7:]  # Remove 'Bearer ' prefix
    
    # Use constant-time comparison to prevent timing attacks
    return hmac.compare_digest(provided_key, api_key)

def set_security_headers(response):
    """Set security headers on response"""
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    response.headers['Content-Security-Policy'] = "default-src 'self'"
    return response

def set_cors_headers(response):
    """Set CORS headers for cross-origin requests"""
    response.headers['Access-Control-Allow-Origin'] = '*'
    response.headers['Access-Control-Allow-Methods'] = ', '.join(ALLOWED_METHODS)
    response.headers['Access-Control-Allow-Headers'] = 'Content-Type, Authorization, X-Requested-With'
    response.headers['Access-Control-Max-Age'] = '3600'
    return response

